class Solution {
    public int[] gardenNoAdj(int n, int[][] paths) {
        List<Integer>[] graph = new List[n + 1];
        for (int i = 1; i <= n; i++) {
            graph[i] = new ArrayList<>();
        }
        for (int[] path : paths) {
            graph[path[0]].add(path[1]);
            graph[path[1]].add(path[0]);
        }
        int[] res = new int[n + 1];
        for (int i = 1; i <= n; i++) {
            Set<Integer> set = new HashSet<>();
            for (int j : graph[i]) {
                if (res[j] != 0) {
                    set.add(res[j]);
                }
            }
            for (int j = 1; j <= 4; j++) {
                if (!set.contains(j)) {
                    res[i] = j;
                    break;
                }
            }
        }
        int[] ans = new int[n];
        for (int i = 1; i <= n; i++) {
            ans[i - 1] = res[i];
        }
        return ans;
    }
}
